import React, { useState } from 'react';

const App = () => {
  const [message, setMessage] = useState('');
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white rounded-lg p-4 w-full max-w-md mx-auto">
        <div className="flex items-center mb-4">
          <div className="bg-[#B7D7CD] rounded-full w-12 h-12 mr-4" />
          <span className="text-lg font-bold">John Doe</span>
        </div>
        <input
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          placeholder="Message"
          className="w-full p-2 mb-4 rounded-lg bg-gray-200"
        />
        <button
className="bg-[#C06C88] py-2 px-4 rounded-lg text-white hover:bg-[#A55E7F]">
          Send
        </button>
      </div>
    </div>
  );
};

export default App;
